DROP TABLE IF EXISTS dashboard_kpis;
CREATE TABLE dashboard_kpis (id SERIAL PRIMARY KEY, name VARCHAR(50), value NUMERIC, unit VARCHAR(20), trend VARCHAR(20), trend_value NUMERIC);
DROP TABLE IF EXISTS dashboard_heatmap;
CREATE TABLE dashboard_heatmap (id SERIAL PRIMARY KEY, day INTEGER, level_name VARCHAR(20), x_coord INTEGER, y_coord INTEGER, intensity NUMERIC);
DROP TABLE IF EXISTS surveillance_cameras;
CREATE TABLE surveillance_cameras (id SERIAL PRIMARY KEY, name VARCHAR(100), location VARCHAR(100), rtmp_url VARCHAR(255), status VARCHAR(20), lat NUMERIC, lng NUMERIC);
DROP TABLE IF EXISTS map_markers;
CREATE TABLE map_markers (id SERIAL PRIMARY KEY, type VARCHAR(50), lat NUMERIC, lng NUMERIC, name VARCHAR(100), status VARCHAR(20));
DROP TABLE IF EXISTS mining_sensor_history CASCADE;
DROP TABLE IF EXISTS mining_sensors CASCADE;
DROP TABLE IF EXISTS mining_sensor_types CASCADE;
DROP TABLE IF EXISTS mining_sensor_categories CASCADE;
CREATE TABLE mining_sensor_categories (id SERIAL PRIMARY KEY, name VARCHAR(100), description TEXT);
CREATE TABLE mining_sensor_types (id SERIAL PRIMARY KEY, category_id INTEGER REFERENCES mining_sensor_categories(id), name VARCHAR(100), unit VARCHAR(20));
CREATE TABLE mining_sensors (id SERIAL PRIMARY KEY, type_id INTEGER REFERENCES mining_sensor_types(id), name VARCHAR(100), lat NUMERIC, lng NUMERIC, status VARCHAR(20), current_value NUMERIC);
CREATE TABLE mining_sensor_history (id SERIAL PRIMARY KEY, sensor_id INTEGER REFERENCES mining_sensors(id), value NUMERIC, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
